export default class LocalStorageManager{constructor(){}getItem(r){try{const t=localStorage.getItem(r);return t?JSON.parse(t):null}catch(r){return console.error(`Error getting item from localStorage: ${r.message}`),null}}setItem(r,value){try{return localStorage.setItem(r,JSON.stringify(value)),!0}catch(r){return console.error(`Error setting item in localStorage: ${r.message}`),!1}}removeItem(r){try{return localStorage.removeItem(r),!0}catch(r){return console.error(`Error removing item from localStorage: ${r.message}`),!1}}clear(){try{return localStorage.clear(),!0}catch(r){return console.error(`Error clearing localStorage: ${r.message}`),!1}}}